        ["1141"] = "An old and rusted bronze sword given by Trader Simplon, who said it was a 'Sword of Trial'. Take this to Master Auron.",
        ["1143"] = "A letter written by Trader Simplon. Take this to Master Auron.",
        ["1144"] = "A cut leg of a dead Venomous Spider or an Arachnid Tracker. Collect twenty of these and take to Master Auron.",
        ["1145"] = "Take this medallion and go to the Grand Master of the Warrior's Guild to change your occupation to a Warrior.",
        ["1150"] = "Spellbook needed to learn Wind Strike.",
        ["1151"] = "Spellbook needed to learn Self Heal.",
        ["1152"] = "Spellbook needed to learn Heal. Used by Human Mystics, Elven Mystics and Dark Mystics.\\nRequired level: 7",
        ["1153"] = "A letter from Sentry Jenna to Master Harant.",
        ["1154"] = "An adamantite sword newly issued to sentries.",
        ["1155"] = "An adamantite sword newly issued to sentries.",
        ["1156"] = "An adamantite sword newly issued to sentries.",
        ["1157"] = "A bronze sword used in the past by sentries. Recover this and take it to Sentry Jenna.",
        ["1158"] = "A bone fragment obtained from the undead skeletons. Gather 10 bone fragments and 3 Elf skulls, and take them to Unoren.",
        ["1159"] = "The skull of an undead Elf. Gather 10 bone fragments and 3 Elf skulls, and take them to Unoren.",
        ["1160"] = "Gather 13 dark bezoars and take them to Sentry Nelsya.",
        ["1161"] = "Take this sword to the Grand Master of the Fighter Guild to change your occupation to a Knight.",
        ["1162"] = "A gold coin engraved with the mark of the lord of Gludio. Gather three or more of these to end the Trial of the Esquire.",
        ["1163"] = "A gold coin engraved with the mark of the lord of Gludio. Gather three or more of these to end the Trial of the Esquire.",
        ["1164"] = "A gold coin engraved with the mark of the lord of Gludio. Gather three or more of these to end the Trial of the Esquire.",
        ["1165"] = "A gold coin engraved with the mark of the lord of Gludio. Gather three or more of these to end the Trial of the Esquire.",
        ["1166"] = "A gold coin engraved with the mark of the lord of Gludio. Gather three or more of these to end Trial of the Esquire.",
        ["1167"] = "A gold coin engraved with the mark of the lord of Gludio. Gather three or more of these to end the Trial of the Esquire.",
        ["1168"] = "A mark that proves guard membership. As Captain Bathis requested, hunt Bugbear Raiders.",
        ["1169"] = "A necklace worn by Bugbears for incantation purposes. Collect ten of these and visit Captain Bathis.",
        ["1170"] = "As High Priest Raymond requested, go to the Ruins of Despair, defeat the departed spirits of priests, and collect 12 Einhasad crucifixes.",
        ["1171"] = "A holy symbol of Einhasad, the goddess of light. Collect 12 of these and go to High Priest Raymond.",
        ["1172"] = "The mark that distinguishes guard membership. As Captain Bezique requested, hunt giant spiders.",
        ["1173"] = "A severed leg of a dead Venomous Spider. Collect twenty of these and go to Captain Bezique.",
        ["1174"] = "As High Priest Levian requested, kill Langk lizardmen and collect the proof.",
        ["1175"] = "A small sculpture Langk lizardmen carry with them. Collect twenty of these and take them to High Priestess Levian.",
        ["1176"] = "A mark that proves guard membership. As Captain Gilbert requested, hunt giant spiders.",
        ["1177"] = "The husk of a giant spider that you peeled off. Collect twenty of these and take them to Captain Gilbert.",
        ["1178"] = "As High Priest Biotin requested, hunt silent horrors in the Elven Ruins.",
        ["1179"] = "The skull of a long-dead Elf. Collect 10 and take them to High Priest Biotin.",
        ["1180"] = "Captain Bezique's letter to Neti. Find Neti in the Village of Gludin and give her the letter.",
        ["1183"] = "Undead bone pieces. Collect 10 and take them to Neti.",
        ["1184"] = "A proof you received after passing Neti's test. You must take it to Captain Bezique.",
        ["1185"] = "It is written that whoever does away with the Cat's Eye bandits and recovers the stolen goods will be rewarded.",
        ["1186"] = "A fair amount of jewelry the Cat's Eye bandits stole. You must take them to Captain Bezique.",
        ["1187"] = "A rare tome the Cat's Eye bandits stole. You must take it to Captain Bezique.",
        ["1188"] = "An expensive necklace that the Cat's Eye bandits have stolen. You must take it back to Captain Bezique.",
        ["1189"] = "An expensive necklace the Cat's Eye bandits stole. You must take it to Captain Bezique.",
        ["1190"] = "Take this medallion to the Grand Masters of the Fighter Guild to change your occupation to a Rogue.",
        ["1191"] = "A certificate of forbidden book collection given by Priest Zigaunt. Carry this around and collect all the forbidden books.",
        ["1192"] = "A certificate that proves that you represent the religious body. This certificate is given by Priest Zigaunt. Take this to Lionel for covenant.",
        ["1193"] = "The last book of Lioniel. Hand this book to Grand Magister Gallint in the Einhovant School of Magic.",
        ["1194"] = "A forbidden book Simplon sold to Vivyan. Collect five forbidden books and take them to Priest Zigaunt.",
        ["1195"] = "The rest of Simplon's forbidden books. Collect 5 forbidden books and take them to Priest Zigaunt.",
        ["1196"] = "A forbidden book Simplon sold to Praga. Collect 5 forbidden books and take them to Priest Zigaunt.",
        ["1197"] = "A certificate that Gallint gives for safekeeping of forbidden books. Give to Lionel and receive covenant.",
        ["1198"] = "The pendant of his mother that Guard Praga lost in the ruins. Take this to Guard Praga and receive a forbidden book.",
        ["1199"] = "A necklace chain where a pendant used to hang. Recover the pendant from the zombies in the Ruins of Agony to make it complete.",
        ["1200"] = "Lionel's pledge not to use the forbidden book again. Give it to Priest Zigaunt and receive the mark of faith.",
        ["1201"] = "Take this token to the high priest of the temple to change your occupation to a Cleric.",
        ["1202"] = "A letter received from Master Sorius to be given to Blacksmith Kluto in the Village of Gludin.",
        ["1203"] = "A box that Kluto asked to give to Master Sorius.",
        ["1204"] = "Take this brooch to the Grand Master of the Fighter Guild and he will change your occupation to a Knight.",
        ["1205"] = "A piece of topaz obtained from the undead in the ruins. Collect 20 to take to Master Sorius.",
        ["1206"] = "A piece of emerald obtained from the Ol Mahum Novices. Collect 20 of these to take to Blacksmith Kluto.",
        ["1207"] = "Master Reisa's letter to Guard Moretti. Find Guard Moretti and give him the letter.",
        ["1208"] = "A torn piece of letter written by Prias and is not legible. Collect all four torn pieces and take them to Guard Moretti.",
        ["1209"] = "A torn piece of letter written by Prias and is not legible Collect all four torn pieces and take them to Guard Moretti.",
        ["1210"] = "A torn piece of letter written by Prias and is not legible. Collect all four torn pieces and take them to Guard Moretti.",
        ["1211"] = "A torn piece of letter written by Prias and is not legible. Collect all four torn pieces and take them to Guard Moretti.",
        ["1212"] = "An herb that Guard Moretti asked to give to Prias.",
        ["1214"] = "An urgent letter from Guard Moretti to Prias.",
        ["1215"] = "A reply of Prias to the letter from Guard Moretti. Hand this to Moretti.",
        ["1216"] = "A letter written by Guard Moretti to Master Reisa. Take it to Master Reisa.",
        ["1217"] = "Take this recommendation to the Grand Master of the Fighter Guild to change your occupation to an Elven Scout.",
        ["1218"] = "A letter from Rosella to Elven Magister Greenis. Related to ruby, the symbol of fire.",
        ["1219"] = "Material needed to make ruby of magical powers. Collect 5 and take them to Magister Greenis for the magical power ruby.",
        ["1220"] = "Ruby that symbolizes fire. Gather 4 jewels that symbolize nature and take them to Rosella for a token to change occupations.",
        ["1221"] = "Aquamarine that symbolizes water. Gather the 4 jewels that symbolize nature and take them to Rosella for a token to change occupations.",
        ["1222"] = "A very ripe apple. Give it to Thalia for information on the aquamarine of water.",
        ["1223"] = "Leaves used as fertilizer for the Mother Tree. Collect five leaves and give them to Thalia for an aquamarine.",
        ["1224"] = "A book Northwind wanted to borrow. If you give this book to Northwind, you can obtain information on the amethyst.",
        ["1225"] = "An amethyst obtained by killing sukar wererat. Give two to Northwind for nobility amethyst.",
        ["1226"] = "Amethyst that symbolizes wind. Gather 4 jewels that symbolize nature and take them to Rosella for a token to change occupations.",
        ["1227"] = "Rosella's recommendation. If you show this to Varsak, you can get information on the fertility peridot.",
        ["1228"] = "A peridot you can get if you kill a sniper skeleton. If you collect 3 and show them to Varsak, you can get the fertility peridot.",
        ["1229"] = "A peridot that symbolizes the earth. Gather 4 jewels that symbolize nature and take them to Rosella for a token to change occupations.",
        ["1230"] = "Take this token to the Grand Master of the Magician Guild to change your occupation to an Elven Wizard.",
        ["1231"] = "A necklace given by Priest Manuel. Take this and go to the port Gludin to find the girl who works miracles.",
        ["1232"] = "Money from Perrin's swindling. Give it to Allana.",
        ["1233"] = "A diary with records of fraud miracle. Show this to Priest Manuel as proof.",
        ["1234"] = "An order of lizard captain to kidnap the sacred flame of prophecy.",
        ["1235"] = "Take this to the high priest to change your occupation to an Oracle.",
        ["1236"] = "Half of the diary given by Allana. You must get money from Perrin and find the other half of the diary.",
        ["1237"] = "A talisman inscribed with palus runes that symbolize a deep lake. Carry this and hunt lycanthrope in the Neutral Zone.",
        ["1238"] = "A skull obtained after killing lycanthrope. Collect thirteen and take them to Master Virgil.",
        ["1239"] = "A letter written by Master Virgil. Take this to Abyssal Celebrant Kalinta of the village of Gludin.",
        ["1240"] = "A talisman with inscription of rune of Morte, symbol of death. Carry this and find materials needed for coffin.",
        ["1241"] = "The hard carapace of a Venomous Spider. Take this and five Arachnid Tracker Silk threads to Abyssal Celebrant Kalinta.",
        ["1242"] = "Arachnid Tracker web threads. Take five of these and a giant Venomous Spider carapace to Abyssal Celebrant Kalinta.",
        ["1243"] = "A coffin used in funeral of Dark Elven Knight. Take this to Master Virgil.",
        ["1244"] = "Take this token to the Grand Master of the Fighter Guild to change your occupation to a Knight.",
        ["1245"] = "A letter received from Triskel. Go to Witch Arkenia of the Altar of Rites.",
        ["1246"] = "A letter received from Arkenia. Take this to Guard Leikan to obtain information about the thief.",
        ["1247"] = "A simple contract given by Guard Leikan. Must hunt moonstone beasts and collect their molars.",
        ["1248"] = "A molar obtained after killing a moonstone beast. Collect 10 of these to take to Guard Leikan.",
        ["1249"] = "A knife received as present from Leikan. They say it works well against the Calpicos.",
        ["1250"] = "Magic liquid stolen from the Altar of Rites. Give this to Witch Arkenia.",
        ["1251"] = "A token of thanks received from Arkenia. Take this to Triskel.",
        ["1252"] = "Take this to the Grand Master of the Dark Elf Guild to change your occupation to an Assassin.",
        ["1253"] = "A seed obtained from Charkeren, who is full of anger. Take this to Witch Varika.",
        ["1254"] = "A seed obtained from Witch Varika. You must obtain all four seeds to earn the Dark Jewel.",
        ["1255"] = "A seed obtained from Annika, who is full of horror. Take this to Witch Varika.",
        ["1256"] = "A seed obtained from a lunatic. Take this to Witch Varika.",
        ["1257"] = "Remains of Charkeren's slain family. Find 3 and return to Charkeren.",
        ["1258"] = "A medicine Varika made for the son of Duchess Dwell. If you give it to Duchess, you can obtain the Seed of Despair.",
        ["1259"] = "The knee bone of undead that Annika was looking for. Give this to Annika to obtain the Seed of Horror.",
        ["1260"] = "The hearts of those who have been turned into skeletons by a sorcerer of lunacy. Collect 3 Hearts of Lunacy and take them to Arkenia.",
        ["1261"] = "Take this token to the Grand Master of the Dark Elf guild to change your occupation to a Dark Wizard.",
        ["1262"] = "The letter of introduction written by Magister Sidra. Take this to Magister Talbot.",
        ["1263"] = "A blank scroll. Take this and hunt dark succubus to obtain bloody runes.",
        ["1264"] = "Runes written with the blood of dark succubus. Collect 5 and take to Magister Talbot.",
        ["1265"] = "The sacred book of Gran Kain, god of darkness, written in elven language. One of two books Sidra told you to find.",
        ["1266"] = "The widely beloved prayer book. Take this to Priest Adonius in the village of Gludin.",
        ["1267"] = "The mark that shows one is in the course of repenting one's sins. Carry this and hunt skeletons and zombies in the Ruins of Despair.",
        ["1268"] = "Bones from the skeletons and zombies in the Ruins of Despair. Gather 10 and take them to Priest Adonius.",
        ["1269"] = "The sacred book of Einhasad, goddess of light, written in the Elven language. One of two books Sidra told you to find.",
        ["1270"] = "Take this token to a Grand Master of a Dark Elf Guild in any major city to change your occupation to a Shillien Oracle.",
        ["1271"] = "A mark that indicates an esquire. Wander around the villages in Gludio and meet with guard captains and high priests.",
        ["1272"] = "Greenis's good luck charm. Kill pincer spiders and give 5 red down to Greenis.",
        ["1273"] = "Sap of Mother Tree that dryad elders like. Find 5 gold leaves and give them to Thalia.",
        ["1274"] = "Northwind's lucky potpourri. Give Northwind 2 amethysts obtained from killing sukar wererats.",
        ["1275"] = "Tamil's necklace. Show it to Perrin.",
        ["1276"] = "A memo from Blacksmith Kluto asking to defeat the Ol Mahum Novices.",
        ["1277"] = "A bronze key. Hunt zombies in the swamp area, collect 3 remains, and take them to Charkeren.",
        ["1278"] = "A candle that lights up the dark. Collect 2 knee bones from the undead and give them to Annika for the Seed of Horror.",
        ["1279"] = "Fragrant herb potpourri. Obtain 3 Hearts of Lunacy from a skeleton scout and take them to Arkenia.",
        ["1280"] = "A map given by the Flame Salamander. Kill ratman fighters and give the key of flame to the salamander in exchange for the token of fire.",
        ["1281"] = "The key that can be obtained by killing a ratman fighter. When you give it to a salamander, he will give you the token of fire.",
        ["1282"] = "The token of fire given by fire spirit salamander. Collect four tokens and give them to Parina to receive the token that enables changing occupations.",
        ["1283"] = "The mirror given by the Wind Sylph. Go to the lizardmen of the Wastelands and obtain the Wind Feather and return it to the Wind Sylph.",
        ["1284"] = "The feather hidden by the Wind Sylph near the Wastelands. Return this to the Wind Sylph to receive a Wind Token.",
        ["1285"] = "The Wind Token given to you by the Wind Spirit Sylph. Collect all four tokens and give them to Parina to receive a special token that will enable you to change occupations.",
        ["1286"] = "Kill water seer and take two sparkle pebbles to water Undine for the token of water.",
        ["1287"] = "Kill water seer in Lake Fellmere for stones. If you give this to Water Undine, she will give you the token of water.",
        ["1288"] = "The token of water given by water spirit Undine. Collect four tokens and give them to Parina to receive the token that enables changing occupations.",
        ["1289"] = "The coin given by earth snake. Kill red bear and give red soil to earth snake for Token of Earth.",
        ["1290"] = "The soil obtained from killing red bear. Give to the earth snake for the token of earth.",
        ["1291"] = "Token of Earth given by earth snake. Collect 4 tokens and give them to Parina to receive the token that enables changing occupations.",
        ["1292"] = "Take this bead to the high priest of the temple to change your occupation to a Wizard.",
        ["1293"] = "The key that unlocks Prias's shackles. Take this and go to Prias.",
        ["1294"] = "Spellbook needed to learn Defense Aura. Used by Elven Fighters and Dark Fighters.\\nRequired level: 5",
        ["1334"] = "Collect 100 predator's fangs and take them to Pixy Murika.",
        ["1335"] = "A sturdy club made from thick tree branches and carried by goblins. Take this to Treant Bremac.",
        ["1336"] = "A broken glass piece. Can be sold in any shop for a low price.",
        ["1337"] = "Can be sold in any shop for a high price.",
        ["1338"] = "A blue jewel. Can be sold in any shop.",
        ["1339"] = "A black jewel. Can be sold in any shop.",
        ["1340"] = "The leaf of a silvery mistletoe. Can be sold in any shop.",
        ["1341"] = "An arrow made from a piece of sharpened bone. It is used as an arrow for a D-Grade bow.",
        ["1342"] = "A powerful arrow made of steel. It is used as an arrow for a C-Grade bow.",
        ["1343"] = "A steel arrow plated with silver.",
        ["1344"] = "A steel arrow plated with Mithril.",
        ["1345"] = "The most powerful arrow. Unknown material.",
        ["1346"] = "A stone found within the remains of a destroyed golem. Take this to Trader Rorento.",
        ["1347"] = "The carcass of monster eye. Take this to Trader Sarien.",
        ["1348"] = "The digestive organ of a basilisk. Take this to Trader Sarien.",
