        ["1419"] = "An item needed to upgrade a clan to level three.",
        ["1420"] = "A list of cooking ingredients from Jonas. Mandragora essence. Honey. Dionian potato. Marsh moss. Floating eye meat.",
        ["1421"] = "A picture that shows what a mandragora looks like. You need this to get mandragora roots.",
        ["1422"] = "Red mandragora root. Collect these to take them to Trader Sonia.",
        ["1423"] = "Rare white mandragora root. Collect these to take them to Trader Sonia.",
        ["1424"] = "Red mandragora sap. One of the five ingredients needed for Jonas's cooking.",
        ["1425"] = "Transparent mandragora sap. One of the ingredients needed for Jonas's cooking.",
        ["1426"] = "A diagram that depicts the drawing of a bee. You must possess this in order to obtain nectar and royal jelly from the bloody bee or the stinger wasp.",
        ["1427"] = "Honey water taken from a giant bee. Collect 20 of these to take them to Guard Jacob.",
        ["1428"] = "A rare ingredient that can be taken only from newborn working bees. Collect these and take them to Guard Jacob.",
        ["1429"] = "Honey made from the nectar you collected from bees. One of the five ingredients needed for Jonas's cooking.",
        ["1430"] = "Golden honey made from the nectar and the royal jelly you collected from bees. One of the five ingredients needed for Jonas's cooking.",
        ["1431"] = "A contract Grocer Pano gave you. It says, if you kill Hobgoblins and bring 30 pieces of proof, he will give you potatoes as a reward.",
        ["1432"] = "An amulet made of a feather that Hobgoblins carry on their bodies. Collect 30 of these and take them to Grocer Pano.",
        ["1433"] = "The highest-quality potatoes grown in the rich soil of southern Dion. One of the five ingredients needed for Jonas's cooking.",
        ["1434"] = "A picture that explains how to collect moss. You need this to collect marsh moss from grey ants or crimson ants.",
        ["1435"] = "Green marsh moss is sometimes used in cooking. Collect this and take it to Priestess Glyvka.",
        ["1436"] = "Rare brown marsh moss, its flavors are superior to the green ones. Collect this and take it to Priestess Glyvka.",
        ["1437"] = "A bundle of well-cared-for moss, collected from a marshy place for cooking. One of the five ingredients needed for Jonas's cooking.",
        ["1438"] = "A bundle of well-cared-for moss, collected from a marshy place for cooking. One of the five ingredients needed for Jonas's cooking.",
