        ["2509"] = "The power of a higher-level spirit is bestowed upon a weapon causing its M. Atk. to momentarily increase. Used with a no grade weapon.",
        ["2510"] = "The power of a higher-level spirit is bestowed upon a weapon causing its M. Atk. to momentarily increase. Used with a D-grade weapon.",
        ["2511"] = "The power of a higher-level spirit is bestowed upon a weapon causing its M. Atk. to momentarily increase. Used with a C-grade weapon.",
        ["2512"] = "The power of a higher-level spirit is bestowed upon a weapon causing its M. Atk. to momentarily increase. Used with a B-grade weapon.",
        ["2513"] = "The power of a higher-level spirit is bestowed upon a weapon causing its M. Atk. to momentarily increase. Used with an A-grade weapon.",
        ["2514"] = "The power of a higher-level spirit is bestowed upon a weapon causing its M. Atk. to momentarily increase. Used with an S-grade weapon.",
        ["2515"] = "When the hunger gauge of a wolf reaches 55% or below, its food will be consumed automatically.",
        ["2627"] = "A mark given to those who have passed the Trial of the Challenger. An item for occupational change.",
        ["2628"] = "Kash's introduction letter. Take this letter to Martien in Town of Giran.",
        ["2629"] = "An item obtained from the monster, Gorr. Take this to Martien in Town of Giran.",
        ["2630"] = "An item obtained from the monster, Baraham. Show this to Raldo and...",
        ["2631"] = "An ancient scroll obtained by slaying Shyslassys. Take this to Kash in the Town of Dion.",
        ["2632"] = "A key obtained by slaying Shyslassys. This key is needed in order to open the Chest of Shyslassys.",
        ["2633"] = "A mark given to those who have passed the Trial of Duty. An item for occupational change.",
        ["2634"] = "A letter given by Dustin. Deliver the letter to Grand Master Hannavalt in Town of Giran.",
        ["2635"] = "Obtained from the spirit of Sir Herod. Take this to Sir Aaron Tanford.",
        ["2636"] = "This is needed in order to speak with the ghost of Sir Talianus. Use this to defeat the hangman tree.",
        ["2637"] = "Obtained from the ghost of Sir Talianus. Take this to Sir Kiel Nighthawk.",
        ["2638"] = "You may obtain this by hunting strains and ghouls. Gather 10 pieces and put them together to create Talianus's report.",
        ["2639"] = "The completed report. After speaking with Sir Kiel Nighthawk, deliver the report to the ghost of Sir Talianus.",
        ["2640"] = "This item can be obtained from Isael Silvershadow. Take it to Priest Dustin.",
        ["2641"] = "You can receive this item when you catch a Leto lizardman. Collect 20 of them and take them to Isael Silvershadow.",
        ["2642"] = "An object received from Priest Dustin. Deliver this to Sir Windawood.",
        ["2643"] = "You can obtain this item from a Breka orc overlord. Take it to Priest Dustin along with Athebaldt's ribs and Athebaldt's shin.",
        ["2644"] = "You can obtain this item from a Breka orc overlord. Take it to Priest Dustin along with Athebaldt's skull and Athebaldt's shin.",
        ["2645"] = "You can obtain this item from a Breka orc overlord. Take it to Priest Dustin along with Athebaldt's ribs and Athebaldt's skull.",
        ["2646"] = "A letter received from Sir Colin Windawood. Show this to Priest Dustin.",
        ["2647"] = "A letter sent from Master Dufner to Master Terry in the Town of Dion.",
        ["2648"] = "Investigate the neer ghoul berserkers of the Execution Grounds.",
        ["2649"] = "Investigate the Ol Mahum captain, Turek orc warlord, ant captain and Turak bugbear warrior.",
        ["2650"] = "A letter sent by Master Terry to Trader Viktor of Hunters Village.",
        ["2651"] = "A letter sent by Trader Viktor to Master Terry in the Town of Dion. The letter has Terry's seal.",
        ["2652"] = "A letter sent by Hawkeye to Trader Viktor of the Hunters Village.",
        ["2653"] = "A mysterious Spirit Ore obtained after slaying neer ghoul berserkers. Take this to Master Terry.",
        ["2654"] = "A mysterious Spirit Ore obtained after slaying the Ol Mahum captain. Take this to Master Terry.",
        ["2655"] = "A mysterious Spirit Ore obtained after slaying the Turek orc overlord. Take this to Master Terry.",
        ["2656"] = "A mysterious Spirit Ore obtained after slaying the ant captain. Take this to Master Terry.",
        ["2657"] = "A mysterious Spirit Ore obtained after slaying the Turak bugbear warrior. Take this to Master Terry.",
        ["2658"] = "A chest containing the mysterious Spirit Ore. Take this to Trader Viktor of the Hunters Village.",
        ["2659"] = "A request issued by Trader Viktor. \"Please gather 10 medusa scales.\"",
        ["2660"] = "The scales of the medusa. Gather 10 of these and take them to Trader Viktor.",
        ["2661"] = "Strange Spirit Ore obtained from the bodies of mutant species. They seem to be related to Shilen, the goddess of death.",
        ["2662"] = "A request letter sent to Magister Marina of the Ivory Tower from Trader Viktor. The letter asks Marina to analyze the dark bezoar.",
        ["2663"] = "A letter sent by Magister Marina to Blacksmith Brunon of the Dwarven Village.",
        ["2664"] = "Experimental tools crafted by Blacksmith Brunon. Deliver these to Magister Marina of the Ivory Tower.",
        ["2665"] = "A document where Magister Marina has organized the analyzed results of the Dark Bezoar. Deliver this to Master Terry in the Town of Dion.",
        ["2666"] = "Master Terry's orders. The orders give instructions to come back for the next task after reaching level 36.",
        ["2667"] = "A list of the bezoar hosts. \"Marsh stakato drone, Breka orc overlord, ant warrior captain, Leto lizardman warrior\"",
        ["2668"] = "The dark bezoar retrieved from the body of a marsh stakato drone. Take this to Master Terry.",
        ["2669"] = "The Spirit Ore retrieved from the body of the Breka orc overlord. Take this to Master Terry.",
        ["2670"] = "The Spirit Ore retrieved from the body of the ant captain. Take this to Master Terry.",
        ["2671"] = "The Spirit Ore retrieved from the body of the Leto lizardman warrior. Take this to Master Terry.",
        ["2672"] = "A report detailing information about the Spirit Ore incident. Take this to Master Dufner of Town of Giran.",
