        ["2704"] = "A plain letter envelope with no contents. The envelope is addressed \"To Warehouse Keeper Raut\".",
        ["2705"] = "A ring given by Drunkard Triff. Show this ring to those whom Triff has entrusted with the Scriptures of Knowledge.",
        ["2706"] = "The 1st book of the Scriptures of Knowledge. Gather all 4 books.",
