        ["3319"] = "The gem that can be obtained by killing a nameless revenant. Find all 6 of Aklantoth gems and take them to Orim the Shadow.",
        ["3320"] = "The gem that can be obtained by slaying a skeletal mercenary. Find all 6 of Aklantoth gems and take them to Orim the Shadow.",
        ["3321"] = "The gem that can be obtained by slaying a skeletal mercenary. Find all 6 of Aklantoth gems and take them to Orim the Shadow.",
        ["3322"] = "The gem that can be obtained by slaying a skeletal mercenary. Find all 6 of Aklantoth gems and take them to Orim the Shadow.",
        ["3323"] = "A mark left behind by the Drevanul Prince Zeruel when escaping from his binds.",
        ["3324"] = "A set of instructions written by Orim of the Shadow. The instructions are to bring back the Sword of Binding and Soul Trap Crystal.",
        ["3325"] = "A letter from Orim of the Shadow to Sir Karol Vasper of the Town of Gludin. The letter asks for the loan of the Sword of the Seal.",
        ["3326"] = "A letter from Orim of the Shadows to Magister Iker of Town of Giran. The letter asks for the loan of the Soul-trap Crystal.",
        ["3327"] = "A letter from Sir Klaus Vasper to Vadin of the Town of Oren. The letter gives permission for the use of the Sword of Binding.",
        ["3328"] = "A holy crucifix of the order, given by Vadin. Take this and go hunt Tamlin Orcs.",
        ["3329"] = "Amulets that the Tamlin Orcs carry for sorcery purposes. Gather 20 of these and take them to Vadin.",
        ["3330"] = "A sanctions letter from Vadin allowing for the use of the Sword of Binding. Take this to Sir Klaus Vasper of the Town of Gludin.",
        ["3331"] = "An amulet given by Magister Iker. It is said to have powers of protection against evil...",
