        ["4239"] = "Cargo that Trader Arodin needs to send to the Dark Elves. Find all 20 of them and take them to Trader Tyra.",
        ["4240"] = "A note from Trader Tyra. Take it to Trader Arodin in Gludin Village.",
        ["4241"] = "First piece of a ranger's report. Find all 4 pieces and take them to Guard Alvah.",
        ["4242"] = "Second piece of a ranger's report. Find all 4 pieces and take them to Guard Alvah.",
        ["4243"] = "Third piece of a ranger's report. Find all 4 pieces and take them to Guard Alvah.",
        ["4244"] = "Fourth piece of a ranger's report. Find all 4 pieces and take them to Guard Alvah.",
        ["4245"] = "The contract that was carried by an Ol Mahum General. It is stamped with the Mark of the Dwarves. Take it to Guard Alvah.",
        ["4246"] = "An operation order that was carried by an Ol Mahum General. Take it to Guard Alvah.",
        ["4247"] = "Certificate that verifies one's membership to the Silver Scale Guild.",
        ["4248"] = "The war supplies that the Dwarven trader Rolento promised to send to Turek orcs. First, show it to Guard Alvah.",
        ["4249"] = "A severed head of an Ol Mahum captain. Collect 30 of them and take them to Turek Chief Burai.",
        ["4250"] = "Jade gemstone from the Enchanted Valley. Collect them and take them to Bentley of Hunters Village.",
        ["4251"] = "A statue of a goddess from an old empire that has been discovered in the cemetery. Take it to Priestess Flownia of Town of Aden.",
        ["4252"] = "A statue created by the ancient sculptor Berona. Take it to Trader Galibredo of the Town of Oren.",
        ["4253"] = "Collect 50 eyes of the Shadow and take them to Warehouse Keeper Sorint.",
        ["4254"] = "The certificate that allows one to participate in a Battle Royal. This game is played by grade 1 members of the Coin Collectors Club.",
        ["4255"] = "The cargo boxes that have been robbed from the wagon of the Trade Guild. Collect 30 of them and take them to Guard Weisz.",
        ["4256"] = "The Crucifix of the goddess of Einhasad. This article was left by Priestess Agnes after her death. Take it along with Agnes's Rosary to Priest Adonius.",
        ["4257"] = "A rosary used while praying. It was left by Priestess Agnes after her death. Take it along with the Crucifix of the goddess of Einhasad to Priest Adonius.",
        ["4258"] = "A black colored totem that exudes an evil aura. Take it to High Priestess Levian.",
        ["4259"] = "The pelts obtained by hunting bears. Collect 20 of them and take them to Grocer Pano of Floran Village.",
        ["4260"] = "Beheaded head of an Enku Orc. Collect 100 of them and take them to Orc Lady Jennifer.",
        ["4261"] = "A bouquet made by tying 100 orc heads together. On behalf of Jennifer who is shy, deliver it to High Prefect Drikus.",
        ["4262"] = "A bouquet made by tying 100 orc heads together. On behalf of Jennifer who is shy, deliver it to Priest Manuel.",
        ["4263"] = "A bouquet made by tying 100 orc heads together. On behalf of Jennifer who is shy, deliver it to Vuku Chief Driko.",
        ["4264"] = "A bouquet made by tying 100 orc heads together. On behalf of Jennifer who is shy, deliver it to Seer Somak.",
        ["4265"] = "A bouquet made by tying 100 orc heads together. On behalf of Jennifer who is shy, deliver it to Prefect Dowki.",
        ["4266"] = "A bouquet made by tying 100 orc heads together. On behalf of Jennifer who is shy, deliver it to Warden Endrigo.",
        ["4267"] = "A bouquet made by tying 100 orc heads together. On behalf of Jennifer who is shy, deliver it to Captain Lucas.",
        ["4268"] = "The box that a man who is smitten by Orc Lady Jennifer asked this to be delivered to her. What do you think is in the box...?",
        ["4269"] = "The articles of dead soldiers who were sent as an expeditionary force 1,000 years ago. These articles have been collected by hunting cave servants. Take them to Antharas Watchman Gilmore.",
        ["4270"] = "An article left by a dead soldier. His descendent Sir Kristof Rodemai is living in Town of Giran. Take it to him.",
        ["4271"] = "An article left by a dead soldier. His descendant Duelist Kaien is living in the Town of Oren. Take it to him.",
        ["4272"] = "An article left by a dead soldier. His descendent, High Prefect Garvarentz, is living in Hunters Village. Take it to him.",
        ["4273"] = "An article left by a dead soldier. Take it to High Priest Orven of Einhasad Temple in Town of Aden where the dead soldier used to be stationed.",
        ["4274"] = "The arm bone of a victim who has been eaten by a Crokian. Collect the five types of bones and take them to Xenovia.",
        ["4275"] = "The thigh bone of a victim who has been eaten by a Crokian. Collect the five types of bones and take them to Xenovia.",
        ["4276"] = "The skull of a victim who has been eaten alive by a Crokian. Collect the five types of bones and take them to Xenovia.",
        ["4277"] = "The rib bone of a victim who has been eaten by a Crokian. Collect the five types of bones and take them to Xenovia.",
        ["4278"] = "The spine of a victim who has been eaten by a Crokian. Collect the five types of bones and take them to Xenovia.",
        ["4279"] = "An urn that contains the bones of all the victims. Ask Mad Doctor Orpheus to resurrect the victims.",
        ["4280"] = "Useless bone pieces obtained after hunting Crokians. If you take them to Orpheus, perhaps something good will happen...?",
        ["4281"] = "The magic powder bought from Magister Xenovia. Throw it along with the victims' bones into the Psychic Medium's Urn.",
        ["4282"] = "A sack containing a victim's soul. An urn was possessed by the victim's soul. Take it to Locksmith Dorothy.",
        ["4283"] = "What are you waiting for? You promised to help me! Release me from this curse immediately! I must regain my appearance as soon as possible!!!",
        ["4284"] = "Powder made by grinding dried flies. Use it when you fail in your attempt to transform a frog.",
        ["4285"] = "The latest model of calculator. Take it to Blacksmith Brunon.",
        ["4286"] = "Crystal obtained by slaying a gemstone beast. Collect 10 of these and take them to Blacksmith Silvera.",
        ["4287"] = "The Titan's Powerstone that has been extracted from the corpse of a Giant. Take it to Magister Hanellin.",
        ["4288"] = "A letter that Hanellin entrusted you with. Take it to Magister Harne of the Dark Elven Village and receive your next assignment from her.",
        ["4289"] = "A letter that Hanellin entrusted you with. Take it to Claudia Athebaldt of Town of Aden and receive your next assignment from her.",
        ["4290"] = "A letter that Hanellin entrusted you with. Take it to Martien of the Town of Giran and receive your next assignment from him.",
        ["4291"] = "The key that was found upon the corpse of the guardian of the sacred ark. Use this key to open the sacred ark and retrieve the sacred object.",
        ["4292"] = "The key that was taken after killing Elberos, the guardian of the sacred ark. Use the key to open the sacred ark and retrieve the sacred object.",
        ["4293"] = "The key that was taken after killing Shadowfang, the guardian of the sacred ark. Use the key to open the sacred ark and retrieve the sacred object.",
        ["4294"] = "A large piece of white cloth given by Magister Hanellin. Kill the Platinum Tribe Shamans and Overlords and soak the cloth with their blood.",
        ["4295"] = "A piece of cloth soaked in the blood of angels and the Platinum race. Hanellin has told you that in order to challenge Baium, you must wrap this blood-soaked cloth around your body.",
        ["4296"] = "The order states that you should hunt Tasaba Lizardmen and Tasaba Lizardman Shaman and bring back their fangs as proof.",
        ["4297"] = "The fangs that have been collected as proofs that Tasaba Lizardmen and Tasaba Lizardman Shaman have been hunted.",
        ["4298"] = "This seems to be the cargo that was stolen from Iason Heine's wagon by Tasaba Lizardmen.",
        ["4299"] = "This document was found in the cargo of the Trade Guild. The document contains various information regarding Innadril. How could this have happened...?",
