        ["4309"] = "A book consisting of 10 pages of operation orders bound together. Who should we take it to...?",
        ["4310"] = "The bill's face value is 1,000 adena. If you take it to Roman of the Blacksmith Guild in Innadril, you can use it to purchase various ingredients.",
        ["4311"] = "Gillian's diary. The last entry was made one year ago.",
        ["4312"] = "Partial lyrics of a song Gillian was jotting down.",
        ["4313"] = "An unfinished music score of a song that Gilian composed for a former lover.",
        ["4314"] = "The heart that Gillian threw out to forget his feelings of love. Return it to the Revenant of Gillian.",
        ["4315"] = "The sacred object of the Gandi Tribe that has been recovered from Bugbears. Take it to Gandi Chief Chianta in the Town of Dion.",
        ["4316"] = "A flute that Troubadour Swan had obtained as a gift for Musician Nanarin.",
        ["4317"] = "A love letter that Troubadour Swan wants to send to Musician Nanarin along with the flute. Take them to Musician Nanarin.",
        ["4318"] = "A gift that Musician Nanarin is sending to Musician Barbado. Take it to Barbado.",
        ["4319"] = "A gift that Musician Nanarin is sending to Musician Barbado. Take it to Barbado.",
        ["4320"] = "A gift that Musician Nanarin is sending to Musician Barbado. Take it to Barbado.",
        ["4321"] = "Black beer that was stolen from Jonas. Take it to Trader Sabrin.",
        ["4322"] = "Event clothes that were stolen from Trader Sonia. Take them to Guard Xaber.",
        ["4323"] = "The key given by Bard Swan. Use this key to open the clothes chest and retrieve the event clothes.",
        ["4324"] = "The key given by Bard Swan. Use this key to open the beer chest and get the black beer out of it.",
        ["4325"] = "A leaf given by Fairy Mimyu to put on the fairy's neck wound that was inflicted by a Hatchling.",
        ["4326"] = "Heads of Ratman Scavengers that you hunted after receiving a request from Katari. Collect 10 of them and take them to Katari.",
        ["4327"] = "The tails of Turek war Hounds that Piotur asks you to catch. Collect 10 of them and take them to Piotur.",
        ["4328"] = "Tyrant Kingpin's Heart. Take it to Elder Casian.",
        ["4329"] = "The venom sacs of Trisalim Tarantulas that Magister Joan asked you to hunt. Collect three and take them to Magister Joan.",
        ["4330"] = "A heavy set of manacles forged at the Black Judge's behest. Take them to the Black Judge.",
        ["4331"] = "Blacksmith's Frame x 1, Steel x 5, Adamantite Nugget x 2, Silver Nugget x 10, Cokes x 10",
        ["4332"] = "A mark that can be obtained by catching a Tarlk Bugbear or a Tarlk Basilisk. Collect 30 and take them to a Clan Hall Herald.",
        ["4333"] = "A certificate that one can present to participate in the hunt for Tarlk Basilisks, a preliminary contest for a Clan Hall Siege War.",
        ["4334"] = "Bodily fluids extracted from ants or ant captains. Collect 20 and take them to Elder Casian.",
        ["4335"] = "The nerve tissue harvested from a Noble Ant's head. Take it to Elder Casian along with the Ant's Ichor.",
        ["4336"] = "Enzyme created by Elder Casian. Find the Ant Larvae sleeping within the  Ant Nest Dungeon and administer the enzyme to them.",
        ["4337"] = "Pelts obtained from alligators caught on Alligator Island. You can sell it to Enverun.",
        ["4338"] = "Leather from Blue Back Alligators caught on Alligator Island. You can sell it to Enverun at a high price.",
        ["4339"] = "A piece of Jewel Studded Alligator Leather caught on Alligator Island. You can sell it to Enverun at a high price.",
        ["4340"] = "If you take a sufficient amount of Alligator Leather and show it to Gabana, a master leather craftsman, you can have an Alligator Leather Belt made.",
        ["4341"] = "If you take a sufficient amount of Alligator Leather and show it to Gabana, a master leather craftsman, you can have an Alligator Leather Purse made.",
        ["4342"] = "A lump of crystal that contains the energy of water. You should find the Stone Statue of Water and dedicate it to the statue.",
        ["4343"] = "A lump of crystal that contains the energy of fire. You should find the Stone Statue of Fire and dedicate it to the statue.",
        ["4344"] = "A lump of crystal that contains the energy of wind. You should find the Stone Statue of Wind and dedicate it to the statue.",
        ["4345"] = "A lump of crystal that contains the energy of earth. You should find the Stone Statue of Earth and dedicate it to the statue.",
        ["4346"] = "A lump of crystal that contains the energy of darkness. You should find the Stone Statue of Darkness and dedicate it to the statue.",
        ["4347"] = "A lump of crystal that contains the energy of light. You should find the Stone Statue of Light and dedicate it to the statue.",
        ["4348"] = "Jade crystals that had been gathered from the Enchanted Valley. Collect them and take them to Bentley of Hunters Village.",
        ["4349"] = "A statue of a goddess that was created by the ancient sculptor Berona in ancient times.",
        ["4350"] = "A statue created by the ancient sculptor Berona. It has not been evaluated by antique experts yet.",
        ["4351"] = "A statue created by Berona, an ancient sculptor. - Prototype",
        ["4352"] = "A statue created by Berona, a sculptor in ancient times. - Original",
        ["4353"] = "Replicated statues that have been created by present day sculptors who imitated Berona's works.",
        ["4354"] = "Forgeries that have been created in imitation of the ancient sculptor Berona's works.",
        ["4355"] = "Special Coin",
        ["4356"] = "Special Coin",
        ["4357"] = "Special Coin",
        ["4358"] = "Special Coin",
        ["4359"] = "A barrel that is filled to the brim with delicious and fragrant liquor. The barrel is very heavy.",
        ["4360"] = "A scarab that is transparent and shines like a precious stone. Among hustlers it is traded at a high price.",
        ["4361"] = "A type of flower that is believed to have the power to heal sickness. It is a favorite of elves.",
        ["4362"] = "It is a strange looking statue of a living creature that looks like an imp. It is an orc's favorite item.",
        ["4363"] = "A very attractive scarlet Aden-style dress designed for a virtuous lady.",
        ["4364"] = "It is made by cutting Nebulite into a spherical shape. Take this to Magic Trader Cema in Hardin's Academy.",
        ["4365"] = "An exotic tasting liqueur made from ectoplasm. Very popular among connoisseurs.",
        ["4366"] = "The winning trophy that Prince Malcom won in a dance competition. You can sell it at a store or keep it as a souvenir.",
        ["4367"] = "The autobiography of Prince Malcom that bears his hand-written signature. Sell it at a store.",
        ["4368"] = "A statue of Prince Malcom made of pure gold. Although quite ugly, it will fetch a handsome price.",
        ["4369"] = "A beautiful and elaborate handkerchief decorated with a flower pattern and lace. Its design could attract the attention of princes and princesses.",
        ["4370"] = "A luxuriously designed goblet. It seems to be an object made during the period of the Elmo Aden Empire.",
        ["4371"] = "A staff that gives off dark M. Atk. On its handle, the words \"Great Demon King\" are engraved.",
        ["4372"] = "Perfume used by Succubus noblewomen. A very strong fragrance, not popular among Elves and Humans.",
        ["4373"] = "A mirror used by Succubus noblewomen when they put on cosmetics. It is also said to be used occasionally by blood queens.",
        ["4374"] = "A heart-shaped stone piece that gives off the aura of dark M. Atk. On its reverse, the words \"I love you Merkenis!\" are engraved.",
        ["4375"] = "A totem made by carving out a whole lump of red granite.",
        ["4376"] = "A walnut sized bead that is smeared with dirt. Perhaps, it is a pearl.",
        ["4377"] = "The tusk of a boar that looks somewhat similar to the ivory of an elephant.",
        ["4378"] = "A large sized sweet potato that was just plucked out of the soil. You s it or roast it. It will make a delicious treat.",
        ["4379"] = "White lion's sharp claws. It is rumored that it is being traded among collectors at a high price.",
        ["4380"] = "A white lion's luxuriant mane. It is rumored to be sold at a high price among collectors.",
        ["4381"] = "Rare medicine imported from the Orient.",
        ["4382"] = "A jar containing sweet honey.",
        ["4383"] = "The gall of a bear that is known to be highly effective in promoting one's health and well-being as well as having mysterious healing properties.",
        ["4384"] = "A fresh salmon that seems to have been just caught from a river.",
        ["4385"] = "The Schuttgart type sushi rice ball. The delicious seasoning of well minced meat gets absorbed into the rice and produces a wonderful taste.",
        ["4386"] = "Exotic spice that has been imported from Avella of the Orient.",
        ["4387"] = "Rabbit weed that is supposed to bring luck. It is the favorite food of rabbits and elpys.",
        ["4388"] = "A check of tremendous face value signed by Prince Malcom. It can be cashed at a warehouse in Town of Giran.",
        ["4389"] = "A key for a private deposit box located in a warehouse in Town of Giran.",
        ["4390"] = "A royal seal made of carved jade. It is engraved with the seal of the Dwarven royal family.",
        ["4391"] = "A king's crown made of gold. It is engraved with the seal of the Dwarven royal family.",
        ["4392"] = "A dance manual that details ballroom dancing techniques. This book will make you a dancing hero!",
        ["4393"] = "Allows one to perform a simple calculation.",
        ["4394"] = "A mark of Hanellin. Along with your companions each carrying a red flower and yellow flower respectively, go to Town of Aden to see her.",
        ["4395"] = "A mark of Hanellin. Along with your companions each carrying a white flower and yellow flower respectively, go to Town of Aden to see her.",
        ["4396"] = "A mark of Hanellin. Along with your companions each carrying a white flower and red flower respectively, go to Town of Aden to see her.",
        ["4397"] = "The book of Saint Solina. Take it along with the blood of a Saint and the bough of a Saint to Magister Hanellin.",
        ["4398"] = "The blood of Saint Solina, hardened into a dark-colored substance contained in a glass bottle. Take it, along with the Book of Saint and the Bough of Saint to Magister Hanellin.",
        ["4399"] = "The Scepter of Saint Solina. It appears to be just a dead dry tree branch. Take it along with the book of a Saint and the blood of a Saint and take it to Magister Hanellin.",
        ["4400"] = "A large piece of white cloth given by Magister Hanellin. Hanellin will tell you its purpose.",
        ["4401"] = "Activates a Dimensional Vortex. Allows you to move to the 1st to 3rd floor of the Tower of Insolence.",
        ["4402"] = "Activates a Dimensional Vortex. Allows you to move to the 4th to 6th floor of the Tower of Insolence.",
        ["4403"] = "Activates a Dimensional Vortex. Allows you to move to the 7th to 10th floor of the Tower of Insolence.",
        ["4404"] = "A broken shard of the green Dimensional Stone. Collect these and take them to Researcher Kaplan.",
        ["4405"] = "A broken shard of the blue Dimensional Stone. Collect these and take them to Researcher Euclie.",
        ["4406"] = "A broken shard of the red Dimensional Stone. Collect these and take them to Researcher Pitagon.",
        ["4407"] = "Its value is 1000 adena, redeemable by Roman of the Blacksmith Guild in Innadril. You can use it to buy various ingredients.",
        ["4408"] = "Posthumously released musical score of Gillian. If you take it to Maestro Melody, you can have an echo crystal made.",
        ["4409"] = "The musical score for the Battle March of Flames. If you take it to Maestro Melody, you can have an echo crystal made.",
        ["4410"] = "A musical score composed by Troubadour Swan. If you take it to Maestro Melody, you can have an echo crystal made.",
        ["4411"] = "An echo crystal that plays the theme music of a journey. May only be used once.",
        ["4412"] = "An echo crystal that plays the theme music of a battle.",
        ["4413"] = "An echo crystal that plays the theme music of love. May only be used once.",
        ["4414"] = "An echo crystal that plays the theme music of solitude. May only be used once.",
        ["4415"] = "An echo crystal that plays the theme music of a feast. May only be used once.",
        ["4416"] = "An echo crystal that plays the theme music of a celebration. May only be used once.",
        ["4417"] = "An echo crystal that plays the theme music of a comedy. May only be used once.",
        ["4418"] = "A musical score containing the theme music of a celebration. If you take it to Maestro Melody, you can have an echo crystal made.",
        ["4419"] = "A musical score containing the theme music of a comedy. If you take it to Maestro Melody, you can have an echo crystal made.",
        ["4420"] = "A musical score composed by Musician Nanarin. If you take it to Maestro Melody, you can have an echo crystal made.",
        ["4421"] = "A musical score composed by Musician Barbado. If you take it to Maestro Melody, you can have an echo crystal made.",
        ["4422"] = "A bugle used to summon a Wind Strider. This pet uses some of the experience points earned by its master.",
        ["4423"] = "A bugle used to summon a Star Strider. This pet uses some of the experience points earned by its master.",
        ["4424"] = "A bugle used to summon a Twilight Strider. This pet uses some of the experience points earned by its master.",
        ["4425"] = "The heavy manacles used to summon a Sin Eater. Summoning the Sin Eater consumes all the summoner's Exp. The Sin Eater must be fed Food for Wolves.",
        ["4426"] = "Having consumed your sins, the Sin Eater has disappeared, leaving you with this ordinary pair of manacles. To repeat this quest, take them back to the Black Judge.",
        ["4427"] = "An Alligator Leather Belt designed and created by Verche, a master leather craftsman.",
        ["4428"] = "An Alligator Leather Belt designed and created by Verche, a master leather craftsman. It is made from a rare blue type of Leather.",
        ["4429"] = "An Alligator Leather Belt designed and created by Verche, a master leather craftsman. It is made from a Leather that is studded with rare jewels.",
        ["4430"] = "An Alligator Leather Purse designed and created by Verche, a master leather craftsman.",
        ["4431"] = "An Alligator Leather Purse designed and created by Verche, a master leather craftsman. It is made from a rare blue type of Leather.",
        ["4432"] = "An Alligator Leather Purse designed and created by Verche, a master leather craftsman. It is made of Leather studded with rare jewels.",
        ["4433"] = "Elemental stone powder obtained from a stone statue in the Forgotten Temple. Can be sold at any store or taken to Magister Nell.",
        ["4434"] = "The shards of elemental stones obtained from stone statues in the Forgotten Temple. Can be sold at any store or taken to Magister Nell.",
        ["4435"] = "The lumps of elemental stone obtained from stone statues in the Forgotten Temple. Can be sold at any store or taken to Magister Nell.",
        ["4436"] = "A request to find and bring back jade crystals from creatures such as Fline, Liele, Satyr etc. that inhabit the Enchanted Valley.",
        ["4437"] = "A request to recover the works of the ancient sculptor Berona from Hatar Ratmen and Vanor Silenos in the area near the Cemetery.",
        ["4438"] = "An essential ingredient needed by a Dwarf to make a Knuckle Duster. It can be bought from a regular store.",
        ["4439"] = "An essential ingredient needed by a Dwarf to make an Avadon Shield. It can be bought from a regular store.",
        ["4440"] = "For Dwarves only. The recipe for a Knuckle Duster. Requires Create Item - Skill Level 5. The success rate is 100%.",
