        ["5858"] = "A magical scroll that transports you to your clan hall. If you don't belong to a clan that possesses a clan hall, this scroll will have no effect.",
        ["5859"] = "A magical scroll that transports you to your castle. If you don't belong to a clan that controls a castle, this scroll will have no effect.",
        ["5860"] = "Lienrik's egg. It's the item that Pet Manager Rood of Heine asked you to find for him.",
        ["5861"] = "Lienrik's shiny red egg. Pet Manager Rood of Heine asked you to find it for him, but...?",
        ["5862"] = "In order to obtain the power of darkness, you will first need to secure this item. Take it to Trader Galman in Dragon Valley.",
        ["5863"] = "Sharp canine tooth of the Alligator. Bring this to the warehouse keeper of Heine.",
        ["5864"] = "A faded piece of paper. Possibly part of a map.",
        ["5865"] = "A tissue sample collected from a spore zombie from the Sea of Spores. It is used as research material by Magister Gauen of the Ivory Tower.",
        ["5866"] = "A spore sample collected from a rotting tree from the Sea of Spores. It is used as research material by Magister Gauen of the Ivory Tower.",
        ["5867"] = "A jade crystal collected from the Enchanted Valley. Take it to Warehouse Freightman Silva of Hunters Village.",
        ["5868"] = "A snake scale from the bodies of Falibati and Trives. Take it to Grand Master Oltran of Town of Aden.",
        ["5869"] = "Remains of residents of Aden Castle who were killed during the Aden-Elmore war. Collect 60 of them and take them to High Priest Orven.",
        ["5870"] = "A document made from collected mysterious document pieces. Take it to Guard Coleman.",
        ["5871"] = "A piece of document that seems to contain some suspicious contents. If you collect 5 of them, you may be able to decipher the information the document conveys.",
        ["5872"] = "Supply items for Taik Orcs. Take it to Guard Coleman and he will give you a reward.",
        ["5873"] = "A treasure chest that was obtained by slaying Zaken's followers. Take it to Warehouse Keeper Randolf of Town of Giran.",
        ["5874"] = "Sairon's hair. Take it to Magister Dieter of Town of Giran.",
        ["5875"] = "It is called a Titan lamp. It is not lit.",
        ["5876"] = "It is called a Titan lamp. It is burning dimly.",
        ["5877"] = "It is called a Titan lamp. It is lit.",
        ["5878"] = "It is called a Titan lamp. It is lit.",
        ["5879"] = "It is called a Titan lamp. It is shining brightly.",
        ["5880"] = "A broken Titan lamp. Take it to Lorain.",
        ["5881"] = "A fang that was obtained from killing a blade stakato. Take it to Eva's Priestess Restina in Heine.",
        ["5882"] = "A flare shard obtained from the Forgotten Temple. Take it to Magister Nell of Gludin Village.",
        ["5883"] = "A water shard obtained from the Forgotten Temple. Take it to Magister Nell of Gludin Village.",
        ["5884"] = "An ingredient used by Orc Shamans during a ritual. Take it to Seer Manakia.",
        ["5885"] = "An ingredient used by Orc Shamans during their ritual. Take it to Seer Manakia.",
        ["5886"] = "A pebble that radiates a strange aura. It sends out a dim light.",
        ["5887"] = "A pebble that radiates a strange aura. It is shining brightly.",
        ["5888"] = "An ingredient used by Orc Shamans during a ritual. Take it to Seer Manakia.",
        ["5889"] = "An ingredient used by Orc Shamans during a ritual. Take it to Seer Manakia.",
        ["5890"] = "A book obtained from The Giant's Cave. Written in an ancient language, its contents cannot be deciphered.",
        ["5891"] = "A simple dictionary published by scholars of ancient times. By using this, you can interpret some of the texts of the Titans.",
        ["5892"] = "A dictionary published by scholars of ancient times. By using this, you can interpret the entire texts of the Titans.",
        ["5893"] = "One of the ingredients used to make wine. Collect 80 of them and take them to Guard Harlan located in the Town of Dion.",
        ["5894"] = "A magical stone used by Enku Orc Shamans when they cast ice magic. Collect 100 of these and take them to Guard Harlan located in the Town of Dion.",
        ["5895"] = "A fruit with a tough, hard outer skin and a fragrant smell. Collect 4 of these and take them to Magister Rollant in the Town of Dion.",
        ["5896"] = "A flower that is said to bloom only under moonlight. Collect 20 of these and take them to Magister Rollant in the Town of Dion.",
        ["5897"] = "The bodily fluids of a Leech that can be obtained from the Cruma Marshlands. Collect 10 of these and take them to Magister Rollant in the Town of Dion.",
        ["5898"] = "It's a coin collectors' dream! Take it to Head Blacksmith Vergara.",
        ["5899"] = "A coin owned by Sorcerer Kail who used to be an aid of Beleth. Take it to Warehouse Keeper Sorint.",
        ["5900"] = "A high quality coin collecting album made of leather.",
        ["5901"] = "Blood that can be obtained by killing a Monster of Offering. The number of this item will determine your score.",
        ["5902"] = "A scroll that contains ancient magic. Take it to Gatekeeper Ziggurat.",
        ["5903"] = "An ancient urn that was found in the Tower of Insolence. Take it to Seer Reva of Town of Aden.",
        ["5904"] = "A small gemstone that is given by Wesley. This item is required to use a mixing urn.",
        ["5905"] = "A gemstone that activates the mixing urn in the basement of the Ivory Tower.",
        ["5906"] = "Commemorating the 5th anniversary of Lineage II, this wrapped gift box contains 10 multi-colored honey rice cakes and 1 Lineage II Commemorative Mark. Cannot be exchanged or dropped. Can be stored in a private warehouse.",
        ["5907"] = "Commemorating the 5th anniversary of Lineage II, this wrapped gift box contains 9 multi-colored honey rice cakes and 1 Lineage II Commemorative Mark. Cannot be exchanged or dropped. Can be stored in a private warehouse.",
        ["5908"] = "Red Crystal that absorbs souls, stage 13. Special abilities can be applied to the weapon when absorbing certain amount of souls. Every time it is used, it consumes 26 of MP. However, the Soul Crystal of this stage absorbs souls by itself, so there is no need for using the Soul Crystal to monsters.",
        ["5909"] = "Commemorating the 5th anniversary of Lineage II, this wrapped gift box contains 8 multi-colored honey rice cakes and 1 Lineage II Commemorative Mark. Cannot be exchanged or dropped. Can be stored in a private warehouse.",
        ["5910"] = "Commemorating the 5th anniversary of Lineage II, this wrapped gift box contains 7 multi-colored honey rice cakes and 1 Lineage II Commemorative Mark. Cannot be exchanged or dropped. Can be stored in a private warehouse.",
        ["5911"] = "Green Crystal that absorbs souls, stage 13. Special abilities can be applied to the weapon when absorbing certain amount of souls. Every time it is used, it consumes 26 of MP. However, the Soul Crystal of this stage absorbs souls by itself, so there is no need for using the Soul Crystal to monsters.",
        ["5912"] = "Commemorating the 5th anniversary of Lineage II, this wrapped gift box contains 6 multi-colored honey rice cakes and 1 Lineage II Commemorative Mark. Cannot be exchanged or dropped. Can be stored in a private warehouse.",
        ["5913"] = "Commemorating the 5th anniversary of Lineage II, this wrapped gift box contains 3 multi-colored honey wheat cakes and 1 Lineage II Commemorative Mark. Cannot be exchanged or dropped. Can be stored in a private warehouse.",
        ["5914"] = "Blue Crystal that absorbs souls, stage 13. Special abilities can be applied to the weapon when absorbing certain amount of souls. Every time it is used, it consumes 26 of MP. However, the Soul Crystal of this stage absorbs souls by itself, so there is no need for using the Soul Crystal to monsters.",
        ["5915"] = "A map that was created after putting together the map pieces found on Alligator Island. It appears to have a mark showing the location of treasure!",
        ["5916"] = "A torn piece of paper that seems to have been ripped out of a spellbook. If you double-click it, you can examine it closely.",
