        ["7517"] = "A dish made by Donath.",
        ["7518"] = "A note that has cooking tips written by Donath.",
        ["7519"] = "Lilly's most favorite dessert that is made of a mixture of shaved ice and sweet flavorings.",
        ["7520"] = "Sweet, soft and cold scoop of ice cream.",
        ["7521"] = "When sunlight reflects on it, it shines brightly with a rainbow of colors.",
        ["7522"] = "Food that is dedicated to Saint Agnes. It is tightly sealed to preserve its freshness.",
        ["7523"] = "Food that is dedicated to Saint Agnes. It is tightly sealed to preserve its freshness.",
        ["7524"] = "Food that is dedicated to Saint Agnes. It is tightly sealed to preserve its freshness.",
        ["7525"] = "Food that is dedicated to Saint Agnes. It is tightly sealed to preserve its freshness.",
        ["7526"] = "A dictionary that is used to decipher an ancient language.",
        ["7527"] = "A dictionary that is used to decipher an ancient language.",
        ["7528"] = "A spider's anatomical structure from which spider web is produced.",
        ["7529"] = "A document received from Information Broker Mist. It contains the results of an investigation requested by Magister Justin.",
        ["7530"] = "A document received from Information Broker Mist. It contains the results of an investigation requested by Magister Alminas.",
        ["7531"] = "A document received from Information Broker Mist. It contains the results of an investigation requested by Magister Kamilen.",
        ["7532"] = "A document received from Information Broker Bavarin. It contains the results of an investigation requested by Guard Baird.",
        ["7533"] = "A document received from Information Broker Mist. It contains the results of an investigation requested by High Priest Gregory.",
        ["7534"] = "An ice crystal that is wrapped in fish scales and emits cold, icy air. Since it is beautifully created with a highly skilled hand, it looks like a flower.",
        ["7535"] = "A chunk of purest ice that is made by freezing purified water. It is known to contain the power of the gods from the beginning of the world.",
        ["7536"] = "The beer requested by Blacksmith Feynn. Just touching it makes your hands feel like they are freezing.",
        ["7537"] = "An elaborate meal requested by the Arena Manager. It is said to be eaten by duelists in ancient times to strengthen their stamina the day before their match.",
        ["7538"] = "A soup that is supposed to contain all the nutrition of the fish it is made from. According to legend, depending on the fish you use to make it, it can have the effect of increasing or decreasing one's lifespan.",
        ["7539"] = "A legendary liquor that is made by dipping hot flames into cold, freezing ice. Although it feels cold to the lips it becomes hot in one's body.",
        ["7540"] = "The type of crystal that is needed to store wedding march music.",
        ["7541"] = "The type of crystal that is needed to store birthday party music.",
        ["7542"] = "The heart that is ripped out of the body of a vampire. It is still beating and pumping out blood.",
        ["7543"] = "A piece of brain collected from an undead monster in the Forest of the Dead. It may contain the memory of the moment of its death.",
        ["7544"] = "The remaining bone that is left in the place where a necromancer died and disappeared. Perhaps it was used to transfix the shape of the necromancer.",
        ["7545"] = "A liver that is rotting and emitting a strong stench. It is known to be a source of magical power of undead.",
        ["7546"] = "A piece of top quality meat that is obtained by slaughtering a wild beast of proper age. Only one piece of this high quality meat can be obtained from one beast.",
        ["7547"] = "A piece of meat obtained by slaughtering a wild beast that is too young. Although it may have a pleasant aroma, it doesn't give good flavor when eating it.",
        ["7548"] = "A piece of a map that was once possessed by Monster Eyes.",
        ["7549"] = "A map that contains a plot of the beasts. Take it to Mercenary Captain Sophya.",
        ["7550"] = "A piece of map obtained from the ghostly apparitions that haunt the Execution Grounds.",
        ["7551"] = "A map that contains strange information. By the way, sometime ago, Trader Galladucci complained that one of the maps he was supposed to receive didn't arrive...?",
        ["7552"] = "A fragment of gemstone that can be obtained by hunting Maille Lizardmen.",
        ["7553"] = "A gold colored orb. High Priest Drikus is supposed to be looking for it.",
        ["7554"] = "A magical scroll that relocates you to Talking Island.",
