        ["13749"] = "A small piece obtained on the Aerial Cleft battlefield. Cannot be exchanged or dropped. Though weak, it seems as if a great amount of energy is condensed into it.",
        ["13750"] = "Magic potion that temporarily restores stamina.",
        ["13757"] = "Badge bearing the mark of Gludio territory.",
        ["13758"] = "Badge bearing the mark of Dion territory.",
        ["13759"] = "Badge bearing the mark of Giran territory.",
        ["13760"] = "Badge bearing the mark of Oren territory.",
