        ["13793"] = "Used to hide your name in Kratei's Cube.",
        ["13794"] = "Transformed Object: Block-Flipping Transformation Scroll",
        ["13795"] = "Transformed Object: Block-Flipping Transformation Scroll",
        ["13796"] = "Energy from ghosts that flow through the Seed of Infinity reside within this item. Can be used at Special Product Broker Kirklan.",
        ["13797"] = "A container having a ghosts being flown out of the Seed of Infinity . Seed of Infinity attack/defend reward",
        ["13798"] = "The ruin left when the ghosts have run out of their energy while being flown in the Seed of Infinity. Seed of Infinity collection additional reward",
        ["13799"] = "Contains the treasure of the ancient Giants. Double-click to open it.",
        ["13800"] = "Frog transformation scroll that was given by Secret Agent Colin. Use the scroll to obtain the bead from the Frog King at Narsell Lake.",
        ["13801"] = "Frog transformation scroll that was given by Secret Agent Colin. Use the scroll to obtain candy from Grandma Tess at Narsell Lake.",
        ["13808"] = "Used by Elmoreden Emperor Shunaiman's guards, it can open the door engulfed in the Flame of Lilim inside the Necropolis.",
        ["13810"] = "Letter detailing Gracia's imminent crisis. Deliver it to Commander Keucereus in the Gracia region.",
        ["13811"] = "Introduction received from Keucereus. If you go northwest from Keucereus Alliance Base, you can reach the Seed of Infinity. Deliver this mark to Officer Tepios there.",
        ["13812"] = "Introduction received from Keucereus. Deliver it to Sergeant Allenos, located at the Seed of Destruction west of Keucereus Alliance Base.",
        ["13813"] = "Introduction received from Croop. Deliver it to Guard Hector at the north entrance to Oren Castle and learn about the whereabouts of Contractor Jacob.",
        ["13814"] = "Necklace discovered at contractor Jacob's body.",
        ["13815"] = "Deliver Croop's letter requesting a memorial service for Contractor Jacob to High Priest Hollint in Einhasad's Temple inside Oren Castle.",
        ["13816"] = "Deliver this herb, collected in Enchanted Valley, to Priest Cain near the Town of Oren.",
        ["13817"] = "Deliver Priest Cain's report about the Seven Signs to Sir Gustav Athebaldt in the Town of Oren.",
        ["13818"] = "Introduction received from Sir Athebaldt. Bring it to Secret Agent Colin in the Southern entrance of the town of Aden. ",
        ["13819"] = "A glove received from the Native Kuta. Bring it to the Secret Agent Colin of the town of Aden.",
        ["13820"] = "Bead obtained from the Frog King. Bring it to the Secret Agent Colin of the town of Aden.",
        ["13821"] = "Candy pouch obtained from Grandma Tess. Bring it to the Secret Agent Colin of the town of Aden.",
        ["13822"] = "Identity card of the guards of the Dawn that was given by Lady Claudia. The qualification one needs to enter the Dawn Lord's temple.",
        ["13823"] = "Details a secret contract between Emperor Shunaiman and the Merchant of Mammon regarding the Seven Signs. Deliver it to High Priest Rayment in the Town of Gludio.",
        ["13824"] = "This apparently sealed a promise the Merchant of Mammon made to the Elmoreden Emperor Shunaiman. It seems to be hiding a mysterious power.",
        ["13825"] = "Proof that all Necropolis and Catacombs have been sealed. Deliver it to Emperor Shunaiman (Elmoreden Era).",
        ["13826"] = "A vial of Emperor Shunaiman's blood, which is the key to activate the Necropolis sealing device. Activate the device!",
        ["13827"] = "This allows you meet Franz. Deliver it to High Priest Orven in the Town of Aden.",
        ["13828"] = "This prayer has been passed down from one high-ranking Priest of the Dawn to the next, stretching back to the Elmoreden Era.",
        ["13829"] = "This obscure text is hand-written in ancient ciphers.",
        ["13830"] = "Deliver this tissue sample to Magister Rohmer in the Temple of Einhasad in the Town of Gludio.",
        ["13831"] = "Deliver this tissue sample to Magister Rohmer in the Temple of Einhasad in the Town of Gludio.",
        ["13832"] = "Deliver this tissue sample to Magister Mirien in the Temple of Einhasad in the Town of Dion.",
        ["13833"] = "Deliver this tissue sample to Magister Mirien in the Temple of Einhasad in the Town of Dion.",
        ["13834"] = "Deliver this tissue sample to Magister Minevia in the Temple of Einhasad in the Town of Heine.",
        ["13835"] = "Deliver this tissue sample to Magister Minevia in the Temple of Einhasad in the Town of Heine.",
        ["13836"] = "Deliver this tissue sample to Magister Rovia in the Temple of Einhasad in the Town of Oren.",
        ["13837"] = "Deliver this tissue sample to Magister Rovia in the Temple of Einhasad in the Town of Oren.",
        ["13838"] = "Deliver this tissue sample to Magister Atraxia in the Temple of Einhasad in the Town of Schuttgart.",
        ["13839"] = "Deliver this tissue sample to Magister Atraxia in the Temple of Einhasad in the Town of Schuttgart.",
        ["13840"] = "Deliver this tissue sample to Magister Kayan in the Temple of Einhasad in the Town of Rune.",
        ["13841"] = "Energy from the Dragonkin that infest the Seed of Destruction. Can be used at Special Product Broker Kirklan.",
        ["13844"] = "A supplemental scroll created for adventurers who are inexperienced in collecting Star Stones.",
        ["13846"] = "Obtained after activating the sealing device, it proves that the sealing device was properly sealed. Deliver it to Emperor Shunaiman.",
        ["13847"] = "This piece of doubt seems to possess a wicked power.",
        ["13848"] = "Obtain this ionized set of armor after defeating the Headless Knight who terrorized the natives.",
        ["13849"] = "The signature product of the Town of Dion.",
        ["13850"] = "Epaulette once worn by the Bloody Axe Aide.",
        ["13851"] = "Nebulite Orb requested by the Ivory Tower.",
        ["13852"] = "Contains an account of Inspector Medibal's investigation of the Seed of Destruction. Deliver it to the wounded Guard Ell at Keucereus Alliance Base.",
        ["13853"] = "The destroyed darkness fragment powder, which bore out of the lifeforms of evil when they were destroyed. Collect them and take them to War Mage Artius at Keucereus Alliance Base.",
        ["13854"] = "Obtained by purging the destroyed Darkness Fragment Powder, deliver it to War Mage Artius.",
        ["13855"] = "Fragment piece that looks like it will break at any moment. A sacred light flows out from it. If you are prepared for it to break, the sacred power of this fragment piece may allow you to inflict damage on Witch Tiat of the Dragon of Darkness. Cannot be exchanged or dropped.",
        ["13856"] = "Obtained from Vulture Rider's and Elite Rider's. Deliver them to Dwarf Engineer Lekon at Keucereus Alliance Base as proof of your skill in flying.",
        ["13857"] = "Issued by Dwarven Engineer Lekon. This certificate proves you have the ability to fly safely in Gracian airs.",
        ["13858"] = "Coarse, Red Star Stone fragment. Higher quality Red Star Stone fragments can be extracted when you have more practice.",
        ["13859"] = "Coarse, Blue Star Stone fragment. Higher quality Blue Star Stone fragments can be extracted when you have more practice.",
        ["13860"] = "Coarse, Green Star Stone fragment. Higher quality Green Star Stone fragments can be extracted when you have more practice.",
        ["13861"] = "Materializes after the reckless Sprite of Water is destroyed. Take it to the Male Attribute Master.",
        ["13862"] = "Materializes after the reckless Sprite of Air is destroyed. Take it to Attribute Master Yang.",
        ["13863"] = "Obtained through hunting in the Seed of Infinity. If you take them to Special Products Broker Kirklan you can exchange 5 of these items for a Freed Soul.",
        ["13864"] = "Obtained after defeating Tiat, it represents Tiat's authority and power. Take it to Special Products Broker Kirklan at Keucereus Alliance Base to exchange it for a special item.",
        ["13865"] = "Obtained through hunting in the Seed of Destruction. If you take them to Special Products Broker Kirklan you can exchange 5 of these items for a Dragonkin Charm.",
        ["13866"] = "Obtained in the Seed of Infinity. Take these Restless Souls to Special Products Broker Kirklan to exchange them for a reward.",
        ["13867"] = "Breath of Tiat fragment that can be harvested by collecting in the Seed of Destruction region. If you bring it to the special products broker Kutran at the Kucereus clan outpost, you can exchange it for a useful item.",
        ["13868"] = "Badge of Yehan Klodekus, who degenerated into a Death Knight through M. Atk. of the Seed of Infinity.",
        ["13869"] = "Badge of Yehan Klanikus, who degenerated into a Death Knight through M. Atk. of the Seed of Infinity.",
        ["13870"] = "Crystal left behind after the death of Kohemenus, who degenerated into a Lich through M. Atk. of the Seed of Infinity.",
        ["13871"] = "Take this large golden feather to Dwarven Engineer Lekon at Keucereus Alliance Base and receive a reward.",
        ["13872"] = "Swallowed by the Rok that roams the Seed of Destruction's dungeon or one of its Variant Falcon or Dra Hawk minions. Collect the remains of those who were sacrificed and take them to Soldier Orbyu at Keucereus Alliance Base.",
        ["13873"] = "Swallowed by the Rok that roams the Seed of Destruction's dungeon or one of its Variant Falcon or Dra Hawk minions. Collect the remains of those who were sacrificed and take them to Soldier Orbyu at Keucereus Alliance Base.",
        ["13874"] = "Swallowed by the Rok that roams the Seed of Destruction's dungeon or one of its Variant Falcon or Dra Hawk minions. Collect the remains of those who were sacrificed and take them to Soldier Orbyu at Keucereus Alliance Base.",
        ["13875"] = "Obtained by hunting Floating Skulls and Floating Zombies. Take them to War Mage Artius.",
        ["13876"] = "Proof that you have captured the Banshee Queen. Take it to War Mage Artius.",
        ["13877"] = "Obtained by hunting Variant Drake Wing minions. Collect them and take them to injured Soldier Tenius at Keucereus Alliance Base.",
        ["13878"] = "Obtained from injured Soldier Tenius, this small vial contains spoiled blood that he claims contains the collected anger toward Keucereus. Its true origin is obscure.",
        ["13879"] = "Drake exclusive bait made by combining Drake flesh and a little bit of the rotten blood. If this Drake bait is used when Seed of Destruction is stabilized, one can call the Dead of Destruction, Dius.",
        ["13880"] = "Horn that sprouts out from the body of the Variant Drake. If you bring it to the injured soldier Tenis or soldier Plenos at Keucereus Alliance Base, you can receive a reward.",
