        ["17213"] = "A biography containing the life story of Solina, a saintess of the Elmore-Aden kingdom. This text has been banned throughout the kingdom and is incredibly difficult to find and intact copy. Double click for more information.",
        ["17214"] = "A complete copy of Kaerun's Memoir. It is a detailed look at Solina's life written by Kaerun from his perspective. This book was never circulated but it's original print has been archived inside the monastery. Double click for more information.",
        ["17215"] = "An incomplete portion of Kaerun's Memoir. This is only part of Solina's life story as written by Kaerun. The book is divided into 4 parts and is kept inside the Monastery of Silence. Double click for more information.",
        ["17216"] = "An incomplete portion of Kaerun's Memoir. This is only part of Solina's life story as written by Kaerun. The book is divided into 4 parts and is kept inside the Monastery of Silence. Double click for more information.",
        ["17217"] = "An incomplete portion of Kaerun's Memoir. This is only part of Solina's life story as written by Kaerun. The book is divided into 4 parts and is kept inside the Monastery of Silence. Double click for more information.",
        ["17218"] = "An incomplete portion of Kaerun's Memoir. This is only part of Solina's life story as written by Kaerun. The book is divided into 4 parts and is kept inside the Monastery of Silence. Double click for more information.",
        ["17219"] = "A book chronicling the early life and events of Solina written by Eris, the abbot of the Monastery of Silence. Double click for more information.",
        ["17220"] = "Librarian Sophia has given the catalog card containing the location of the book. Double click for more information.",
        ["17221"] = "Key that opens the passageway gate to the Seal of the Saintess entrance. You can enter the passageway with this key.",
