        ["21981"] = "Clownfish Hat. Uses 2 hair accessory slots. Cannot be exchanged, dropped, or sold.",
        ["21982"] = "Refined Angel Ring. Uses 2 hair accessory slots. Cannot be exchanged, dropped, or sold.",
        ["21983"] = "Refined Wizard Hat. Uses 2 hair accessory slots. Cannot be exchanged, dropped, or sold.",
        ["21984"] = "Refined Jester Hat. Uses 2 hair accessory slots. Cannot be exchanged, dropped, or sold.",
        ["21985"] = "Refined Romantic Chapeau. Uses 2 hair accessory slots. Cannot be exchanged, dropped, or sold.",
        ["21986"] = "Bracelet that summons a cute Antharas Agathion. Cannot be exchanged, dropped, or sold.",
        ["21987"] = "Hat worn by pirates. Uses 2 hair accessory slots. Cannot be exchanged, dropped, or sold.",
        ["21988"] = "Can stand upon the shiny platform with brilliant lighting when equipped. Cannot be exchanged, dropped, or sold.",
        ["21989"] = "Polar bear hat that makes you feel cozy just by looking at it. Uses 2 hair accessory slot(s). Cannot be exchanged, dropped, or sold.",
        ["22173"] = "MP +21, Resistance to Poison +40%, Poison attack rate +40%, Resistance to Hold +30%, Hold attack rate +30%, and increases Accuracy, Critical Damage, and Casting Spd. Only one effect is applied when wearing two of the same ring.",
        ["22174"] = "MP +21, Resistance to Poison +30%, Poison attack rate +30%, Resistance to Hold +20%, Hold attack rate +20%, and increases Accuracy and Critical Damage. Only one effect is applied when wearing two of the same ring.",
        ["22175"] = "MP +37, Resistance to Bleed +30%, Bleed attack rate +30%, heal amount +15%, vampiric rage effect, Resistance to Shock/Metal attacks +30%, Shock/Metal attack rate +30%, and Resistance to Dark +15. Only one effect is applied even when the same two earrings are worn. If it is equipped together with a standard Earring of Zaken, only the effect of Blessed Earring of Zaken will be applied.",
        ["22183"] = "Graduation Cap. Uses 2 hair accessory slots. Cannot be exchanged, dropped, or sold.",
        ["22184"] = "Admiral's Hat. Uses 2 hair accessory slots. Cannot be exchanged, dropped, or sold.",
        ["22189"] = "Taiwanese child exclusive hat (boy). Uses 2 hair accessory slots. Cannot be exchanged, dropped, or sold. Item that can be stored in a private warehouse.",
        ["22190"] = "Taiwanese child exclusive hat (girl). Uses 2 hair accessory slots. Cannot be exchanged, dropped, or sold. Item that can be stored in a private warehouse.",
        ["22191"] = "Dimensional item\\nCan ride a Rocking Horse when equipped. Can be used for 7 days. Cannot be exchanged or dropped. Can be stored in a private warehouse.",
        ["22192"] = "Dimensional item\\nCan ride a Rocking Horse when equipped. Can be used for 30 days. Cannot be exchanged or dropped. Can be stored in a private warehouse.",
        ["22193"] = "Dimensional item\\nCan ride a Rocking Horse when equipped. Cannot be exchanged or dropped. Can be stored in a private warehouse.",
        ["22200"] = "A bracelet that can summon a Lantern Agathion. The Lantern Agathion's gift cannot be received if there is no room in the inventory and carried item weight. Cannot be exchanged, dropped, or destroyed. Item that can be stored in a private warehouse. ",
        ["22211"] = "Its effects are MP+300, HP+500, CP+1035, increased P. Atk., increased M. Atk., increased M. Crit Rate, and Crit Atk. power. Can be used for 7 days. Cannot be exchanged or dropped. Can be stored in a private warehouse. ",
        ["22212"] = "Its effects are MP+37, HP+250, Vampiric Rage effect, increased accuracy, decreased re-use time for magic skills, and decreased MP consumption for magic skills. When two identical earrings are equipped, only one effect is applied. Can be used for 7 days. Cannot be exchanged or dropped. Can be stored in a private warehouse.",
        ["22213"] = "Its effects are MP+25, increased Atk. Spd., and increased Casting Spd. When two identical rings are equipped, only one effect is applied. Can be used for 7 days. Cannot be exchanged or dropped. Can be stored in a private warehouse.",
        ["22214"] = "Its effects are MP+300, HP+500, CP+1035, increased P. Atk., increased M. Atk., increased M. Crit Rate, and increased Crit Atk. power. Can be used for 30 days. Cannot be exchanged or dropped. Can be stored in a private warehouse. ",
        ["22215"] = "Its effects are MP+37, HP+250, Vampiric Rage effect, increased accuracy, decreased re-use time for magic skills, and decreased MP consumption for magic skills. When two identical earrings are equipped, only one effect is applied. Can be used for 30 days. Cannot be exchanged or dropped. Can be stored in a private warehouse.",
        ["22216"] = "Its effects are MP+25, increased Atk. Spd., and increased Casting Spd. When two identical rings are equipped, only one effect is applied. Can be used for 30 days. Cannot be exchanged or dropped. Can be stored in a private warehouse.",
        ["22237"] = "Dimensional item\\nSummons another player. Both the summoner and the one being summoned must have it equipped. Re-use waiting time is 1 hour. Cannot be exchanged or dropped. Can be stored in a private warehouse. ",
        ["22243"] = "Not In Use",
